1	import { FastifyInstance, FastifyRequest } from 'fastify';
2	import fp from 'fastify-plugin';
3	import { auditLogs } from '@studioops/db/schema';
4	
5	declare module 'fastify' {
6	  interface FastifyRequest {
7	    auditContext?: {
8	      resourceType: string;
9	      resourceId?: string;
10	      action?: string;
11	      beforeState?: unknown;
12	      afterState?: unknown;
13	    };
14	    /** True if audit was already written by the route handler via writeAudit() */
15	    _auditWritten?: boolean;
16	    /** Write audit entry synchronously before sending response. Throws on failure. */
17	    writeAudit: () => Promise<void>;
18	  }
19	}
20	
21	const MAX_RETRY = 3;
22	const RETRY_DELAY_MS = 100;
23	const WRITE_METHODS = new Set(['POST', 'PUT', 'PATCH', 'DELETE']);
24	function sleep(ms: number) { return new Promise(r => setTimeout(r, ms)); }
25	
26	async function insertAuditWithRetry(
27	  db: any,
28	  entry: Record<string, unknown>,
29	  log: any,
30	): Promise<boolean> {
31	  for (let attempt = 1; attempt <= MAX_RETRY; attempt++) {
32	    try {
33	      await db.insert(auditLogs).values(entry);
34	      return true;
35	    } catch (err) {
36	      if (attempt < MAX_RETRY) {
37	        await sleep(RETRY_DELAY_MS * attempt);
38	        continue;
39	      }
40	      log.fatal({ err, auditEntry: entry, retriesExhausted: true },
41	        'AUDIT_FAILURE: Failed to persist audit log after retries.');
42	      return false;
43	    }
44	  }
45	  return false;
46	}
47	
48	function buildAuditEntry(request: FastifyRequest) {
49	  const auditCtx = request.auditContext;
50	  return {
51	    actorId: request.user?.sub || null,
52	    action: auditCtx?.action || `${request.method} ${request.routeOptions?.url || request.url}`,
53	    resourceType: auditCtx?.resourceType || inferResourceType(request.url),
54	    resourceId: auditCtx?.resourceId || null,
55	    beforeState: auditCtx?.beforeState || null,
56	    afterState: auditCtx?.afterState || null,
57	    ipAddress: request.ip,
58	    userAgent: request.headers['user-agent'] || null,
59	  };
60	}
61	
62	async function auditLogPlugin(fastify: FastifyInstance) {
63	  // Decorate every request with writeAudit() for explicit use in routes.
64	  fastify.addHook('onRequest', async (request) => {
65	    request._auditWritten = false;
66	    request.writeAudit = async () => {
67	      const entry = buildAuditEntry(request);
68	      const ok = await insertAuditWithRetry(fastify.db, entry, request.log);
69	      if (!ok) {
70	        throw new Error('AUDIT_PERSISTENCE_FAILURE');
71	      }
72	      request._auditWritten = true;
73	    };
74	  });
75	
76	  // Audit for read operations (GET/HEAD/OPTIONS) via onResponse (best-effort with retry).
77	  // Write operations MUST use writeAudit() in route handlers — no fallback.
78	  fastify.addHook('onResponse', async (request, reply) => {
79	    if (request._auditWritten) return;
80	    if (!request.url.startsWith('/api/v1/') || request.url === '/api/v1/health') return;
81	
82	    // Successful write operations: MUST have called writeAudit() — invariant violation otherwise.
83	    if (WRITE_METHODS.has(request.method) && reply.statusCode < 400) {
84	      const msg = `AUDIT_VIOLATION: ${request.method} ${request.url} (${reply.statusCode}) completed without writeAudit(). Add auditContext + writeAudit() to this route.`;
85	      request.log.fatal({ method: request.method, url: request.url, statusCode: reply.statusCode }, msg);
86	      throw new Error(msg);
87	    }
88	
89	    // All remaining protected requests (reads, failed writes): guaranteed audit with retry.
90	    // If insert fails after retries, emit fatal with full entry for reconciliation.
91	    const entry = buildAuditEntry(request);
92	    const ok = await insertAuditWithRetry(fastify.db, entry, request.log);
93	    if (!ok) {
94	      request.log.fatal({
95	        auditEntry: entry,
96	        method: request.method,
97	        url: request.url,
98	        statusCode: reply.statusCode,
99	      }, 'AUDIT_PERSISTENCE_FAILURE: Protected action completed without durable audit record. Entry logged for mandatory reconciliation.');
100	    }
101	  });
102	}
103	
104	function inferResourceType(url: string): string {
105	  const segments = url.replace('/api/v1/', '').split('/');
106	  return segments[0] || 'unknown';
107	}
108	
109	export default fp(auditLogPlugin, {
110	  name: 'audit-log',
111	  dependencies: ['database'],
112	  fastify: '5.x',
113	});
114	
