1	import { FastifyInstance } from 'fastify';
2	import fp from 'fastify-plugin';
3	import { sql } from 'drizzle-orm';
4	import { AUDIT } from '@studioops/shared';
5	
6	/**
7	 * Audit log retention plugin.
8	 * Runs daily to purge audit entries older than 365 days.
9	 * Calls a SECURITY DEFINER DB function so the app role cannot
10	 * disable immutability triggers directly — only the DB-owned
11	 * function has that privilege.
12	 */
13	async function auditRetentionPlugin(fastify: FastifyInstance) {
14	  const PURGE_INTERVAL_MS = 24 * 60 * 60 * 1000; // 24 hours
15	  let timer: ReturnType<typeof setInterval> | null = null;
16	
17	  async function purgeOldAuditLogs(): Promise<number> {
18	    try {
19	      const result = await fastify.db.execute(
20	        sql`SELECT purge_old_audit_logs(${AUDIT.RETENTION_DAYS}) AS deleted_count`,
21	      );
22	
23	      const count = (result[0] as any)?.deleted_count ?? 0;
24	      if (count > 0) {
25	        fastify.log.info({ count, retentionDays: AUDIT.RETENTION_DAYS }, 'Purged old audit log entries');
26	      }
27	      return count;
28	    } catch (err) {
29	      fastify.log.error({ err }, 'Audit log retention purge failed');
30	      return 0;
31	    }
32	  }
33	
34	  // Schedule daily purge (first run after 1 minute, then every 24 hours)
35	  fastify.addHook('onReady', () => {
36	    setTimeout(() => {
37	      purgeOldAuditLogs();
38	      timer = setInterval(purgeOldAuditLogs, PURGE_INTERVAL_MS);
39	    }, 60_000);
40	  });
41	
42	  fastify.addHook('onClose', () => {
43	    if (timer) clearInterval(timer);
44	  });
45	}
46	
47	export default fp(auditRetentionPlugin, {
48	  name: 'audit-retention',
49	  dependencies: ['database'],
50	  fastify: '5.x',
51	});
