1	import { FastifyInstance } from 'fastify';
2	import { z } from 'zod';
3	import { RegisterUseCase, ValidationError, ConflictError } from '../../core/use-cases/register';
4	import { LoginUseCase, AuthenticationError, LockoutError } from '../../core/use-cases/login';
5	import { RefreshUseCase } from '../../core/use-cases/refresh';
6	import { Argon2Hasher } from '../../infrastructure/crypto/argon2-hasher';
7	import { DrizzleUserRepository } from '../../infrastructure/persistence/user-repository';
8	import { DrizzleSessionRepository } from '../../infrastructure/persistence/session-repository';
9	import { DrizzleLockoutRepository } from '../../infrastructure/persistence/lockout-repository';
10	
11	const registerSchema = z.object({
12	  username: z.string().min(1, 'Username is required').max(100),
13	  password: z.string().min(1, 'Password is required'),
14	});
15	
16	const loginSchema = z.object({
17	  username: z.string().min(1),
18	  password: z.string().min(1),
19	});
20	
21	const refreshSchema = z.object({
22	  refreshToken: z.string().min(1),
23	});
24	
25	export default async function authRoutes(fastify: FastifyInstance) {
26	  const hasher = new Argon2Hasher();
27	  const userRepo = new DrizzleUserRepository(fastify.db);
28	  const sessionRepo = new DrizzleSessionRepository(fastify.db);
29	  const lockoutRepo = new DrizzleLockoutRepository(fastify.db);
30	
31	  const registerUseCase = new RegisterUseCase(userRepo, hasher);
32	  const loginUseCase = new LoginUseCase(userRepo, hasher, sessionRepo, lockoutRepo);
33	  const refreshUseCase = new RefreshUseCase(sessionRepo, async (userId: string) => {
34	    const user = await userRepo.findById(userId);
35	    return user?.role ?? null;
36	  });
37	
38	  // POST /auth/register
39	  fastify.post('/register', async (request, reply) => {
40	    const parseResult = registerSchema.safeParse(request.body);
41	    if (!parseResult.success) {
42	      return reply.status(400).send({
43	        error: 'VALIDATION_ERROR',
44	        message: 'Validation failed',
45	        details: parseResult.error.issues.map((i) => i.message),
46	      });
47	    }
48	
49	    try {
50	      const result = await registerUseCase.execute(parseResult.data);
51	      request.auditContext = { resourceType: 'auth', action: 'auth.register', afterState: { id: result.id, username: result.username } };
52	      await request.writeAudit();
53	      return reply.status(201).send(result);
54	    } catch (err) {
55	      if (err instanceof ValidationError) {
56	        return reply.status(400).send({
57	          error: 'VALIDATION_ERROR',
58	          message: err.message,
59	          details: err.details,
60	        });
61	      }
62	      if (err instanceof ConflictError) {
63	        return reply.status(409).send({
64	          error: 'CONFLICT',
65	          message: err.message,
66	        });
67	      }
68	      throw err;
69	    }
70	  });
71	
72	  // POST /auth/login
73	  fastify.post('/login', async (request, reply) => {
74	    const parseResult = loginSchema.safeParse(request.body);
75	    if (!parseResult.success) {
76	      return reply.status(400).send({
77	        error: 'VALIDATION_ERROR',
78	        message: 'Validation failed',
79	        details: parseResult.error.issues.map((i) => i.message),
80	      });
81	    }
82	
83	    try {
84	      const result = await loginUseCase.execute(parseResult.data);
85	      const accessToken = fastify.jwt.sign(result.accessTokenPayload);
86	
87	      const isSecure = fastify.appConfig?.NODE_ENV === 'production';
88	
89	      // Access token: httpOnly cookie + returned in body (SPA needs it for Authorization header)
90	      reply.setCookie('accessToken', accessToken, {
91	        httpOnly: true, secure: isSecure, sameSite: 'strict',
92	        path: '/', maxAge: result.expiresIn,
93	      });
94	      // Refresh token: httpOnly cookie ONLY — never in response body to minimize XSS exposure
95	      reply.setCookie('refreshToken', result.refreshToken, {
96	        httpOnly: true, secure: isSecure, sameSite: 'strict',
97	        path: '/api/v1/auth', maxAge: 28800,
98	      });
99	
100	      request.auditContext = { resourceType: 'auth', action: 'auth.login' };
101	      await request.writeAudit();
102	
103	      return reply.status(200).send({
104	        accessToken,
105	        expiresIn: result.expiresIn,
106	      });
107	    } catch (err) {
108	      if (err instanceof LockoutError) {
109	        reply.header('Retry-After', String(err.retryAfter));
110	        return reply.status(429).send({
111	          error: 'ACCOUNT_LOCKED',
112	          message: err.message,
113	          retryAfter: err.retryAfter,
114	        });
115	      }
116	      if (err instanceof AuthenticationError) {
117	        return reply.status(401).send({
118	          error: 'INVALID_CREDENTIALS',
119	          message: err.message,
120	        });
121	      }
122	      throw err;
123	    }
124	  });
125	
126	  // POST /auth/refresh
127	  fastify.post('/refresh', async (request, reply) => {
128	    // Accept refresh token from httpOnly cookie or body (backward compat for API tests)
129	    const bodyToken = (request.body as any)?.refreshToken;
130	    const cookieToken = (request as any).cookies?.refreshToken;
131	    const refreshToken = bodyToken || cookieToken;
132	
133	    if (!refreshToken) {
134	      return reply.status(400).send({
135	        error: 'VALIDATION_ERROR',
136	        message: 'Refresh token is required',
137	      });
138	    }
139	
140	    try {
141	      const result = await refreshUseCase.execute({ refreshToken });
142	      const accessToken = fastify.jwt.sign(result.accessTokenPayload);
143	
144	      const isSecure = fastify.appConfig?.NODE_ENV === 'production';
145	
146	      reply.setCookie('accessToken', accessToken, {
147	        httpOnly: true, secure: isSecure, sameSite: 'strict',
148	        path: '/', maxAge: result.expiresIn,
149	      });
150	      reply.setCookie('refreshToken', result.refreshToken, {
151	        httpOnly: true, secure: isSecure, sameSite: 'strict',
152	        path: '/api/v1/auth', maxAge: 28800,
153	      });
154	
155	      request.auditContext = { resourceType: 'auth', action: 'auth.refresh' };
156	      await request.writeAudit();
157	
158	      return reply.status(200).send({
159	        accessToken,
160	        expiresIn: result.expiresIn,
161	      });
162	    } catch (err) {
163	      if (err instanceof AuthenticationError) {
164	        return reply.status(401).send({
165	          error: 'INVALID_TOKEN',
166	          message: err.message,
167	        });
168	      }
169	      throw err;
170	    }
171	  });
172	
173	  // POST /auth/logout
174	  fastify.post('/logout', {
175	    preHandler: [fastify.authenticate],
176	  }, async (request, reply) => {
177	    const body = request.body as { refreshToken?: string } | undefined;
178	    const userId = request.user.sub;
179	
180	    if (body?.refreshToken) {
181	      const { hashRefreshToken } = await import('../../core/domain/refresh-token');
182	      const hash = hashRefreshToken(body.refreshToken);
183	      const token = await sessionRepo.findRefreshTokenByHash(hash);
184	      if (token) {
185	        await sessionRepo.markRefreshTokenUsed(token.id);
186	      }
187	    } else {
188	      await sessionRepo.revokeAllRefreshTokensForUser(userId);
189	    }
190	
191	    request.auditContext = { resourceType: 'auth', action: 'auth.logout' };
192	    await request.writeAudit();
193	    return reply.status(204).send();
194	  });
195	
196	  // GET /auth/session
197	  fastify.get('/session', {
198	    preHandler: [fastify.authenticate],
199	  }, async (request, reply) => {
200	    const user = await userRepo.findById(request.user.sub);
201	    if (!user) {
202	      return reply.status(401).send({
203	        error: 'UNAUTHORIZED',
204	        message: 'User not found',
205	      });
206	    }
207	
208	    // Include the user's primary org (first org membership)
209	    const { DrizzlePermissionRepository } = await import('../../infrastructure/persistence/permission-repository');
210	    const permRepo = new DrizzlePermissionRepository(fastify.db);
211	    const orgIds = await permRepo.getOrgIdsForUser(user.id);
212	
213	    return reply.status(200).send({
214	      id: user.id,
215	      username: user.username,
216	      role: user.role,
217	      orgId: orgIds[0] || null,
218	    });
219	  });
220	
221	  // DELETE /auth/sessions/:userId (Admin only)
222	  fastify.delete('/sessions/:userId', {
223	    preHandler: [fastify.authenticate],
224	  }, async (request, reply) => {
225	    const { userId } = request.params as { userId: string };
226	
227	    if (request.user.role !== 'administrator') {
228	      return reply.status(403).send({
229	        error: 'FORBIDDEN',
230	        message: 'Insufficient permissions',
231	      });
232	    }
233	
234	    const revokedCount = await sessionRepo.revokeAllRefreshTokensForUser(userId);
235	
236	    request.auditContext = { resourceType: 'auth', action: 'auth.revoke_sessions', afterState: { userId, revokedCount } };
237	    await request.writeAudit();
238	    return reply.status(200).send({ revokedCount });
239	  });
240	}
