19	export function parseConfig(env: Record<string, string | undefined> = process.env): AppConfig {
20	  const nodeEnv = env.NODE_ENV || 'development';
21	
22	  // In test/development, allow insecure defaults so local dev and tests work without .env
23	  const effectiveEnv = { ...env };
24	  if (nodeEnv === 'test' || nodeEnv === 'development') {
25	    if (!effectiveEnv.JWT_SECRET) effectiveEnv.JWT_SECRET = INSECURE_JWT_SECRET;
26	    if (!effectiveEnv.ENCRYPTION_KEY) effectiveEnv.ENCRYPTION_KEY = INSECURE_ENCRYPTION_KEY;
27	  }
28	
29	  const result = configSchema.safeParse(effectiveEnv);
30	  if (!result.success) {
31	    const errors = result.error.issues.map(i => `${i.path.join('.')}: ${i.message}`);
32	    throw new Error(`Configuration validation failed:\n${errors.join('\n')}`);
33	  }
