35	  // In production, reject known insecure secrets — hard failure
36	  if (nodeEnv === 'production') {
37	    if (result.data.JWT_SECRET === INSECURE_JWT_SECRET) {
38	      throw new Error('SECURITY: JWT_SECRET must be changed from the default value in production');
39	    }
