43	  }
44	
45	  // In development, warn loudly when using insecure defaults
46	  if (nodeEnv === 'development') {
47	    if (result.data.JWT_SECRET === INSECURE_JWT_SECRET || result.data.ENCRYPTION_KEY === INSECURE_ENCRYPTION_KEY) {
48	      console.warn('');
49	      console.warn('╔══════════════════════════════════════════════════════════════════════╗');
50	      console.warn('║  WARNING: Running with INSECURE default secrets.                     ║');
51	      console.warn('║  Set JWT_SECRET and ENCRYPTION_KEY in .env for any non-local use.    ║');
52	      console.warn('║  In production (NODE_ENV=production), insecure defaults are rejected. ║');
53	      console.warn('╚══════════════════════════════════════════════════════════════════════╝');
54	      console.warn('');
55	    }
56	  }
57	
