52	    action: auditCtx?.action || `${request.method} ${request.routeOptions?.url || request.url}`,
53	    resourceType: auditCtx?.resourceType || inferResourceType(request.url),
54	    resourceId: auditCtx?.resourceId || null,
55	    beforeState: auditCtx?.beforeState || null,
56	    afterState: auditCtx?.afterState || null,
