64	  fastify.addHook('onRequest', async (request) => {
65	    request._auditWritten = false;
66	    request.writeAudit = async () => {
67	      const entry = buildAuditEntry(request);
68	      const ok = await insertAuditWithRetry(fastify.db, entry, request.log);
69	      if (!ok) {
70	        throw new Error('AUDIT_PERSISTENCE_FAILURE');
71	      }
72	      request._auditWritten = true;
73	    };
74	  });
75	
76	  // Audit for read operations (GET/HEAD/OPTIONS) via onResponse (best-effort with retry).
77	  // Write operations MUST use writeAudit() in route handlers — no fallback.
78	  fastify.addHook('onResponse', async (request, reply) => {
79	    if (request._auditWritten) return;
80	    if (!request.url.startsWith('/api/v1/') || request.url === '/api/v1/health') return;
