89	    // All remaining protected requests (reads, failed writes): guaranteed audit with retry.
90	    // Fail-closed: if audit persistence fails after retries, throw to prevent silent completion.
91	    const entry = buildAuditEntry(request);
92	    const ok = await insertAuditWithRetry(fastify.db, entry, request.log);
93	    if (!ok) {
94	      const msg = 'AUDIT_PERSISTENCE_FAILURE: Could not persist audit record for protected action after retries.';
95	      request.log.fatal({
96	        auditEntry: entry,
97	        method: request.method,
98	        url: request.url,
99	        statusCode: reply.statusCode,
100	      }, msg);
101	      throw new Error(msg);
102	    }
103	  });
104	}
