1	/**
2	 * Applies audit immutability triggers to the database.
3	 * Idempotent — safe to run multiple times.
4	 * Used by both Docker entrypoint and local development setup.
5	 */
6	import postgres from 'postgres';
7	
8	export async function applyAuditTriggers(connectionString: string): Promise<void> {
9	  const client = postgres(connectionString, { max: 1 });
10	
11	  console.log('Applying audit immutability triggers...');
12	
13	  await client`
14	    CREATE OR REPLACE FUNCTION prevent_audit_log_mutation()
15	    RETURNS TRIGGER AS $$
16	    BEGIN
17	      RAISE EXCEPTION 'audit_logs table is immutable: % operations are forbidden', TG_OP;
18	      RETURN NULL;
19	    END;
20	    $$ LANGUAGE plpgsql
21	  `;
22	
23	  // Create triggers idempotently (drop-if-exists + create)
24	  await client`
25	    DO $$ BEGIN
26	      CREATE TRIGGER audit_logs_no_update
27	        BEFORE UPDATE ON audit_logs
28	        FOR EACH ROW EXECUTE FUNCTION prevent_audit_log_mutation();
29	    EXCEPTION WHEN duplicate_object THEN NULL;
30	    END $$
31	  `;
32	
33	  await client`
34	    DO $$ BEGIN
35	      CREATE TRIGGER audit_logs_no_delete
36	        BEFORE DELETE ON audit_logs
37	        FOR EACH ROW EXECUTE FUNCTION prevent_audit_log_mutation();
38	    EXCEPTION WHEN duplicate_object THEN NULL;
39	    END $$
40	  `;
41	
42	  // Create a SECURITY DEFINER function for retention purge.
43	  // This runs with the privileges of the DB owner (who created it),
44	  // so the app role cannot disable triggers directly — only call this function.
45	  await client`
46	    CREATE OR REPLACE FUNCTION purge_old_audit_logs(retention_days integer)
47	    RETURNS integer
48	    LANGUAGE plpgsql
49	    SECURITY DEFINER
50	    AS $$
51	    DECLARE
52	      deleted_count integer;
53	    BEGIN
54	      -- Only the purge function (running as definer) can disable the trigger
55	      ALTER TABLE audit_logs DISABLE TRIGGER audit_logs_no_delete;
56	
57	      DELETE FROM audit_logs WHERE created_at < (now() - (retention_days || ' days')::interval);
58	      GET DIAGNOSTICS deleted_count = ROW_COUNT;
59	
60	      ALTER TABLE audit_logs ENABLE TRIGGER audit_logs_no_delete;
61	      RETURN deleted_count;
62	    EXCEPTION WHEN OTHERS THEN
63	      -- Re-enable trigger even on error
64	      ALTER TABLE audit_logs ENABLE TRIGGER audit_logs_no_delete;
65	      RAISE;
66	    END;
67	    $$
68	  `;
69	
70	  // Revoke trigger management from the studioops app role if it exists.
71	  // This prevents the runtime app from disabling audit immutability triggers.
72	  // The SECURITY DEFINER purge function retains necessary privileges.
73	  try {
74	    await client`REVOKE ALL ON FUNCTION prevent_audit_log_mutation() FROM studioops`;
75	    // Revoke ALTER TABLE on audit_logs from app role
76	    await client`REVOKE ALL PRIVILEGES ON TABLE audit_logs FROM studioops`;
77	    await client`GRANT SELECT, INSERT ON TABLE audit_logs TO studioops`;
78	  } catch {
79	    // Role may not exist yet or may be the owner — skip silently
80	  }
81	
82	  console.log('Audit triggers and retention function applied.');
83	  await client.end();
84	}
85	
86	// Run directly
87	const dbUrl = process.env.DATABASE_URL;
88	if (dbUrl) {
89	  applyAuditTriggers(dbUrl).catch((err) => {
90	    console.error('Failed to apply audit triggers:', err);
91	    process.exit(1);
92	  });
93	}
