187	    this.formDuration = event.durationMinutes;
188	    this.formChannel = event.channel;
189	    this.formTags = (event.tags || []).join(', ');
190	    this.formDescription = event.description || '';
191	    this.showCreateForm.set(false);
192	  }
193	
194	  cancelForm(): void {
195	    this.showCreateForm.set(false);
196	    this.editingEvent.set(null);
197	    this.formTitle = ''; this.formEventType = ''; this.formScheduledAt = '';
198	    this.formDuration = 60; this.formChannel = 'website'; this.formTags = ''; this.formDescription = '';
199	  }
200	
201	  async submitEvent(): Promise<void> {
202	    this.submitting.set(true);
203	    const tags = this.formTags.split(',').map(t => t.trim()).filter(Boolean);
204	    try {
205	      if (this.editingEvent()) {
206	        await firstValueFrom(this.http.put(`/api/v1/events/${this.editingEvent()}`, {
207	          title: this.formTitle, description: this.formDescription,
208	          scheduledAt: new Date(this.formScheduledAt).toISOString(),
209	          durationMinutes: this.formDuration, channel: this.formChannel, tags,
210	        }));
211	        this.notifications.success('Event updated');
212	      } else {
213	        await firstValueFrom(this.http.post('/api/v1/events', {
214	          title: this.formTitle, eventType: this.formEventType, description: this.formDescription,
215	          scheduledAt: new Date(this.formScheduledAt).toISOString(),
216	          durationMinutes: this.formDuration, channel: this.formChannel, tags, orgId: this.orgId,
217	        }));
218	        this.notifications.success('Event created');
219	      }
220	      this.cancelForm();
221	      this.load();
222	    } catch (err) {
223	      this.notifications.error(err instanceof HttpErrorResponse ? (err.error?.message || 'Save failed') : 'Save failed');
224	    } finally { this.submitting.set(false); }
225	  }
226	
227	  async changeStatus(eventId: string, status: string): Promise<void> {
228	    try {
229	      await firstValueFrom(this.http.patch(`/api/v1/events/${eventId}/status`, { status }));
230	      this.events.update(list => list.map(e => e.id === eventId ? { ...e, status } : e));
231	      this.notifications.success(`Event ${status}`);
232	    } catch (err) {
233	      this.notifications.error(err instanceof HttpErrorResponse ? (err.error?.message || 'Failed') : 'Failed');
234	    }
235	  }
236	
237	  async register(eventId: string): Promise<void> {
238	    this.registering.set(true);
239	    try {
240	      const res = await firstValueFrom(this.http.post<any>(`/api/v1/events/${eventId}/registrations`, {}));
241	      this.registrationMessage.update(m => ({ ...m, [eventId]: { type: 'success', text: `Registered successfully (status: ${res.status})` } }));
242	    } catch (err) {
243	      const msg = err instanceof HttpErrorResponse ? (err.error?.message || 'Registration failed') : 'Registration failed';
244	      this.registrationMessage.update(m => ({ ...m, [eventId]: { type: 'error', text: msg } }));
245	    } finally { this.registering.set(false); }
246	  }
247	
248	  statusClass(s: string): string {
249	    switch (s) {
250	      case 'confirmed': return 'bg-green-100 text-green-800';
251	      case 'scheduled': return 'bg-blue-100 text-blue-800';
252	      case 'completed': return 'bg-gray-100 text-gray-600';
253	      case 'cancelled': return 'bg-red-100 text-red-800';
254	      default: return 'bg-gray-100 text-gray-600';
255	    }
256	  }
257	
258	  async toggleRegistrations(eventId: string): Promise<void> {
259	    if (this.expandedEvent() === eventId) { this.expandedEvent.set(null); this.registrations.set([]); return; }
260	    this.expandedEvent.set(eventId);
