import fp from 'fastify-plugin';
import { sql } from 'drizzle-orm';
import { AUDIT } from '@studioops/shared';

/**
 * Audit log retention plugin.
 * Runs daily to purge audit entries older than 365 days.
 * Calls a SECURITY DEFINER DB function so the app role cannot
 * disable immutability triggers directly — only the DB-owned
 * function has that privilege.
 */
async function auditRetentionPlugin(fastify: FastifyInstance) {
  const PURGE_INTERVAL_MS = 24 * 60 * 60 * 1000; // 24 hours
  let timer: ReturnType<typeof setInterval> | null = null;

  // Execution telemetry — exposed via /api/v1/health or monitoring
  const telemetry = {
    lastRunAt: null as string | null,
    lastSuccessAt: null as string | null,
    lastErrorAt: null as string | null,
    lastError: null as string | null,
    totalRuns: 0,
    totalSuccesses: 0,
    totalFailures: 0,
    totalPurged: 0,
  };

  fastify.decorate('auditRetentionTelemetry', telemetry);

  async function purgeOldAuditLogs(): Promise<number> {
    telemetry.totalRuns++;
    telemetry.lastRunAt = new Date().toISOString();
    try {
      const result = await fastify.db.execute(
        sql`SELECT purge_old_audit_logs(${AUDIT.RETENTION_DAYS}) AS deleted_count`,
      );

      const count = (result[0] as any)?.deleted_count ?? 0;
      telemetry.totalSuccesses++;
      telemetry.lastSuccessAt = new Date().toISOString();
      telemetry.totalPurged += count;
      fastify.log.info({
        count,
        retentionDays: AUDIT.RETENTION_DAYS,
        telemetry: { totalRuns: telemetry.totalRuns, totalFailures: telemetry.totalFailures },
      }, 'Audit retention purge completed');
      return count;
    } catch (err) {
      telemetry.totalFailures++;
      telemetry.lastErrorAt = new Date().toISOString();
      telemetry.lastError = err instanceof Error ? err.message : String(err);
      fastify.log.error({
        err,
        telemetry: { totalRuns: telemetry.totalRuns, totalFailures: telemetry.totalFailures },
      }, 'Audit log retention purge failed');
      return 0;
    }
  }

  // Schedule daily purge (first run after 1 minute, then every 24 hours).
  // NOTE: This is an in-process scheduler. For guaranteed execution independent of
  // service uptime, consider supplementing with a system-level cron job or DB scheduler
  // that calls purge_old_audit_logs() directly.
  fastify.addHook('onReady', () => {
    setTimeout(() => {
      purgeOldAuditLogs();
      timer = setInterval(purgeOldAuditLogs, PURGE_INTERVAL_MS);
    }, 60_000);
  });

  fastify.addHook('onClose', () => {
    if (timer) clearInterval(timer);
  });
