1	import { FastifyInstance } from 'fastify';
2	import fp from 'fastify-plugin';
3	import { sql } from 'drizzle-orm';
4	import { AUDIT } from '@studioops/shared';
5	
6	declare module 'fastify' {
7	  interface FastifyInstance {
8	    auditRetentionTelemetry: {
9	      lastRunAt: string | null;
10	      lastSuccessAt: string | null;
11	      lastErrorAt: string | null;
12	      lastError: string | null;
13	      totalRuns: number;
14	      totalSuccesses: number;
15	      totalFailures: number;
16	      totalPurged: number;
17	    };
18	    purgeAuditLogs: () => Promise<number>;
19	  }
20	}
21	
22	/**
23	 * Audit log retention plugin.
24	 *
25	 * Exposes `fastify.purgeAuditLogs()` for on-demand invocation (e.g. admin routes)
26	 * and tracks execution telemetry via `fastify.auditRetentionTelemetry`.
27	 *
28	 * Scheduling is handled externally by the `audit-purge-cron` Docker service
29	 * (see docker-compose.yml) which runs `packages/db/src/purge-audit.ts` daily,
30	 * independent of API process uptime. This guarantees retention enforcement even
31	 * when the API is down or restarting.
32	 *
33	 * The purge calls a SECURITY DEFINER DB function so the app role cannot
34	 * disable immutability triggers directly.
35	 */
36	async function auditRetentionPlugin(fastify: FastifyInstance) {
37	  const telemetry = {
38	    lastRunAt: null as string | null,
39	    lastSuccessAt: null as string | null,
40	    lastErrorAt: null as string | null,
41	    lastError: null as string | null,
42	    totalRuns: 0,
43	    totalSuccesses: 0,
44	    totalFailures: 0,
45	    totalPurged: 0,
46	  };
47	
48	  fastify.decorate('auditRetentionTelemetry', telemetry);
49	
50	  async function purgeOldAuditLogs(): Promise<number> {
51	    telemetry.totalRuns++;
52	    telemetry.lastRunAt = new Date().toISOString();
53	    try {
54	      const result = await fastify.db.execute(
55	        sql`SELECT purge_old_audit_logs(${AUDIT.RETENTION_DAYS}) AS deleted_count`,
56	      );
57	
58	      const count = (result[0] as any)?.deleted_count ?? 0;
59	      telemetry.totalSuccesses++;
60	      telemetry.lastSuccessAt = new Date().toISOString();
61	      telemetry.totalPurged += count;
62	      fastify.log.info({
63	        count,
64	        retentionDays: AUDIT.RETENTION_DAYS,
65	        telemetry: { totalRuns: telemetry.totalRuns, totalFailures: telemetry.totalFailures },
66	      }, 'Audit retention purge completed');
67	      return count;
68	    } catch (err) {
69	      telemetry.totalFailures++;
70	      telemetry.lastErrorAt = new Date().toISOString();
71	      telemetry.lastError = err instanceof Error ? err.message : String(err);
72	      fastify.log.error({
73	        err,
74	        telemetry: { totalRuns: telemetry.totalRuns, totalFailures: telemetry.totalFailures },
75	      }, 'Audit log retention purge failed');
76	      return 0;
77	    }
78	  }
79	
80	  fastify.decorate('purgeAuditLogs', purgeOldAuditLogs);
81	}
82	
83	export default fp(auditRetentionPlugin, {
84	  name: 'audit-retention',
85	  dependencies: ['database'],
86	  fastify: '5.x',
87	});
