163	export class DashboardComponent implements OnInit {
164	  private http = inject(HttpClient);
165	  private notifications = inject(NotificationService);
166	
167	  payload = signal<any>(null);
168	  loading = signal(true);
169	  exporting = signal(false);
170	  hasFilePicker = 'showSaveFilePicker' in (typeof window !== 'undefined' ? window : {});
171	  dateFrom = '2026-01-01';
172	  dateTo = '2026-12-31';
173	  dateFromDisplay = '01/01/2026';
174	  dateToDisplay = '12/31/2026';
175	  eventType = '';
176	
177	  orgId = '';
178	  totalEvents = signal(0);
179	  conversionRate = signal('0.0');
180	  attendanceRate = signal('0.0');
181	  cancellationRate = signal('0.0');
182	  maxPopularity = signal(1);
183	
184	  ngOnInit(): void {
185	    this.loadDashboard();
186	  }
187	
188	  async loadDashboard(): Promise<void> {
189	    this.loading.set(true);
190	    try {
191	      let url = `/api/v1/analytics/dashboard?from=${this.dateFrom}&to=${this.dateTo}`;
192	      if (this.orgId) url += `&orgId=${this.orgId}`;
193	      if (this.eventType) url += `&eventType=${this.eventType}`;
194	
195	      const data = await firstValueFrom(this.http.get<any>(url));
196	      this.payload.set(data);
197	
198	      const pop = data.popularity?.data ?? [];
199	      this.totalEvents.set(pop.reduce((a: number, b: number) => a + b, 0));
200	      this.maxPopularity.set(Math.max(1, ...pop));
201	
202	      const funnel = data.conversionFunnel?.counts ?? [0, 0, 0];
203	      this.conversionRate.set(funnel[0] > 0 ? ((funnel[1] / funnel[0]) * 100).toFixed(1) : '0.0');
204	
205	      const att = data.attendanceRate?.rates ?? [0, 0];
206	      this.attendanceRate.set((att[0] * 100).toFixed(1));
207	
208	      const can = data.cancellationRate?.rates ?? [0, 0];
209	      this.cancellationRate.set((can[1] * 100).toFixed(1));
210	    } catch {
211	      this.notifications.error('Failed to load dashboard');
212	    } finally {
213	      this.loading.set(false);
214	    }
215	  }
216	
217	  async exportData(format: string): Promise<void> {
218	    this.exporting.set(true);
219	    try {
220	      const res = await firstValueFrom(
221	        this.http.post(`/api/v1/analytics/export`, {
222	          format,
223	          filters: { from: this.dateFrom, to: this.dateTo, orgId: this.orgId || undefined, eventType: this.eventType || undefined },
224	        }, { responseType: 'blob' }),
225	      );
226	
227	      const ext = format === 'xlsx' ? 'xlsx' : 'csv';
228	      const mimeType = format === 'xlsx'
229	        ? 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet'
230	        : 'text/csv';
231	      const suggestedName = `analytics-${new Date().toISOString().split('T')[0]}.${ext}`;
232	
233	      // File System Access API — save to user-selected local folder
234	      const handle = await (window as any).showSaveFilePicker({
235	        suggestedName,
236	        types: [{
237	          description: format === 'xlsx' ? 'Excel Spreadsheet' : 'CSV File',
238	          accept: { [mimeType]: [`.${ext}`] },
