171	  async load(): Promise<void> {
172	    try {
173	      const res = await firstValueFrom(this.http.get<any>('/api/v1/portfolio'));
174	      this.items.set(res.data);
175	    } finally { this.loading.set(false); }
176	  }
177	
178	  async loadCategories(): Promise<void> {
179	    try {
180	      const res = await firstValueFrom(this.http.get<any>('/api/v1/portfolio/categories'));
181	      this.categories.set(res.data);
182	    } catch { /* ignore */ }
183	  }
