242	    const formData = new FormData();
243	    formData.append('file', file);
244	    formData.append('title', file.name.replace(/\.[^.]+$/, ''));
245	    if (this.uploadCategoryId) {
246	      formData.append('categoryId', this.uploadCategoryId);
247	    }
248	
249	    this.uploadStatus.set('uploading');
250	    this.uploadMessage.set(`Uploading ${file.name}...`);
251	
252	    try {
253	      const res = await firstValueFrom(this.http.post<any>('/api/v1/portfolio/upload', formData));
254	      this.uploadStatus.set('success');
255	      this.uploadMessage.set(`Uploaded "${res.title}" — accepted for processing (status: ${res.status}). Compression and preview generation in progress.`);
256	      this.load();
257	    } catch (err: any) {
258	      this.uploadStatus.set('error');
259	      this.uploadMessage.set(err.error?.message || 'Upload failed');
260	    }
261	
262	    input.value = '';
263	  }
264	}
