1	#!/usr/bin/env node
2	
3	/**
4	 * Cross-platform test runner for StudioOps.
5	 * Runs: unit tests → integration tests → Angular build check → E2E tests (if API running).
6	 * Usage: node scripts/run-tests.js
7	 *
8	 * CI mode: Set CI=true to fail when integration or E2E stages are skipped.
9	 *   CI=true DATABASE_URL=... API_URL=... node scripts/run-tests.js
10	 */
11	
12	import { execSync } from 'node:child_process';
13	import { resolve } from 'node:path';
14	
15	const root = resolve(import.meta.dirname, '..');
16	const strict = process.env.CI === 'true';
17	const skipped = [];
18	
19	function run(label, cmd, cwd = root) {
20	  console.log(`\n--- ${label} ---`);
21	  try {
22	    execSync(cmd, { cwd, stdio: 'inherit', env: { ...process.env, FORCE_COLOR: '1' } });
23	    console.log(`✓ ${label} passed`);
24	  } catch {
25	    console.error(`✗ ${label} FAILED`);
26	    process.exit(1);
27	  }
28	}
29	
30	console.log('=== StudioOps Test Suite ===\n');
31	
32	// 1. Unit tests
33	run('[1/4] API Unit Tests', 'npx vitest run', resolve(root, 'apps/api'));
34	
35	// 2. Integration tests (requires DATABASE_URL)
36	if (process.env.DATABASE_URL) {
37	  run('[2/4] API Integration Tests', 'npx vitest run --config vitest.integration.config.ts', resolve(root, 'apps/api'));
38	} else if (strict) {
39	  console.log('\n--- [2/4] API Integration Tests ---');
40	  console.log('✗ DATABASE_URL not set. CI mode requires integration tests.');
41	  skipped.push('integration');
42	} else {
43	  console.log('\n--- [2/4] API Integration Tests ---');
44	  console.log('⚠ Skipped (DATABASE_URL not set). Set DATABASE_URL to run integration tests.');
45	  skipped.push('integration');
46	}
47	
48	// 3. Angular build (skip in Docker — the web service build already validates this)
49	if (process.env.SKIP_ANGULAR_BUILD !== 'true') {
50	  run('[3/4] Angular Build Check', 'npx ng build --configuration=production', resolve(root, 'apps/web'));
51	} else {
52	  console.log('\n--- [3/4] Angular Build Check ---');
53	  console.log('⚠ Skipped (SKIP_ANGULAR_BUILD=true — web service build validates this).');
54	}
55	
56	// 4. E2E tests (if API is running)
57	const apiUrl = process.env.API_URL || 'http://localhost:3100';
58	try {
59	  const http = await import('node:http');
60	  await new Promise((resolve, reject) => {
61	    http.get(`${apiUrl}/api/v1/health`, (res) => {
62	      if (res.statusCode === 200) resolve(true);
63	      else reject(new Error(`API returned ${res.statusCode}`));
64	    }).on('error', reject);
65	  });
66	  // Run API E2E tests; also run browser tests if APP_URL is available
67	  const appUrl = process.env.APP_URL;
68	  const projects = appUrl ? '' : '--project=api';
69	  run('[4/4] Playwright E2E Tests', `npx playwright test --config e2e/playwright.config.ts ${projects}`, root);
70	} catch {
71	  console.log('\n--- [4/4] Playwright E2E Tests ---');
72	  console.log(`⚠ Skipped (API not reachable at ${apiUrl}). Start API to run E2E tests.`);
73	  skipped.push('e2e');
74	}
75	
76	if (strict && skipped.length > 0) {
77	  console.error(`\n✗ CI mode: ${skipped.join(', ')} stage(s) were skipped. Set DATABASE_URL and API_URL to run all stages.`);
78	  process.exit(1);
79	}
80	
81	console.log('\n=== All available tests passed ===');
