1	import { FastifyInstance, FastifyRequest, FastifyReply } from 'fastify';
2	import fp from 'fastify-plugin';
3	import { CheckPermissionUseCase, ForbiddenError } from '../../core/use-cases/check-permission';
4	import type { AuthContext } from '../../core/use-cases/check-permission';
5	import { DrizzlePermissionRepository } from '../persistence/permission-repository';
6	import type { Role } from '@studioops/shared';
7	
8	declare module 'fastify' {
9	  interface FastifyInstance {
10	    authorize: (resource: string, action: string) => (request: FastifyRequest, reply: FastifyReply) => Promise<void>;
11	  }
12	  interface FastifyRequest {
13	    authContext?: AuthContext;
14	  }
15	}
16	
17	async function rbacPlugin(fastify: FastifyInstance) {
18	  const permRepo = new DrizzlePermissionRepository(fastify.db);
19	  const checkPermission = new CheckPermissionUseCase(permRepo);
20	
21	  // Helper: ensure authContext is populated (called after JWT is verified)
22	  async function ensureAuthContext(request: FastifyRequest): Promise<AuthContext> {
23	    if (request.authContext) return request.authContext;
24	
25	    // Administrator sees all orgs — orgScope must be undefined (not empty array)
26	    const role = request.user.role as Role;
27	    const orgScope = role === 'administrator'
28	      ? undefined
29	      : await permRepo.getOrgIdsForUser(request.user.sub);
30	
31	    request.authContext = {
32	      userId: request.user.sub,
33	      role,
34	      orgScope,
35	    };
36	    return request.authContext;
37	  }
38	
39	  fastify.decorate('authorize', function (resource: string, action: string) {
40	    return async function (request: FastifyRequest, reply: FastifyReply) {
41	      if (!request.user?.sub) {
42	        return reply.status(401).send({
43	          error: 'UNAUTHORIZED',
44	          message: 'Authentication required',
45	        });
46	      }
47	
48	      // Populate authContext (orgScope) after authentication
49	      const authContext = await ensureAuthContext(request);
50	
51	      try {
52	        await checkPermission.execute({
53	          authContext,
54	          resource,
55	          action,
56	        });
57	      } catch (err) {
58	        if (err instanceof ForbiddenError) {
59	          return reply.status(403).send({
60	            error: 'FORBIDDEN',
61	            message: err.message,
62	          });
63	        }
64	        throw err;
65	      }
66	    };
67	  });
68	}
69	
70	export default fp(rbacPlugin, {
71	  name: 'rbac',
72	  dependencies: ['database', 'auth'],
73	  fastify: '5.x',
74	});
