5	declare module 'fastify' {
6	  interface FastifyRequest {
7	    auditContext?: {
8	      resourceType: string;
9	      resourceId?: string;
10	      action?: string;
11	      beforeState?: unknown;
12	      afterState?: unknown;
13	    };
14	    /** True if audit was already written by the route handler via writeAudit() */
15	    _auditWritten?: boolean;
16	    /** Re-entry guard for onSend audit hook */
17	    _auditHookRan?: boolean;
18	    /** Write audit entry synchronously before sending response. Throws on failure. */
19	    writeAudit: () => Promise<void>;
20	  }
21	}
22	
23	const MAX_RETRY = 3;
24	const RETRY_DELAY_MS = 100;
25	const WRITE_METHODS = new Set(['POST', 'PUT', 'PATCH', 'DELETE']);
26	function sleep(ms: number) { return new Promise(r => setTimeout(r, ms)); }
27	
28	async function insertAuditWithRetry(
29	  db: any,
30	  entry: Record<string, unknown>,
31	  log: any,
32	): Promise<boolean> {
33	  for (let attempt = 1; attempt <= MAX_RETRY; attempt++) {
34	    try {
35	      await db.insert(auditLogs).values(entry);
36	      return true;
37	    } catch (err) {
38	      if (attempt < MAX_RETRY) {
39	        await sleep(RETRY_DELAY_MS * attempt);
40	        continue;
41	      }
42	      log.fatal({ err, auditEntry: entry, retriesExhausted: true },
43	        'AUDIT_FAILURE: Failed to persist audit log after retries.');
44	      return false;
45	    }
46	  }
47	  return false;
48	}
49	
50	function buildAuditEntry(request: FastifyRequest) {
51	  const auditCtx = request.auditContext;
52	  return {
53	    actorId: request.user?.sub || null,
54	    action: auditCtx?.action || `${request.method} ${request.routeOptions?.url || request.url}`,
55	    resourceType: auditCtx?.resourceType || inferResourceType(request.url),
56	    resourceId: auditCtx?.resourceId || null,
57	    beforeState: auditCtx?.beforeState || null,
58	    afterState: auditCtx?.afterState || null,
59	    ipAddress: request.ip,
60	    userAgent: request.headers['user-agent'] || null,
61	  };
62	}
63	
64	async function auditLogPlugin(fastify: FastifyInstance) {
65	  // Decorate every request with writeAudit() for explicit use in routes.
66	  fastify.addHook('onRequest', async (request) => {
67	    request._auditWritten = false;
68	    request._auditHookRan = false;
69	    request.writeAudit = async () => {
70	      const entry = buildAuditEntry(request);
71	      const ok = await insertAuditWithRetry(fastify.db, entry, request.log);
72	      if (!ok) {
73	        throw new Error('AUDIT_PERSISTENCE_FAILURE');
74	      }
75	      request._auditWritten = true;
76	    };
77	  });
78	
79	  // --- onSend: synchronous invariant check (no DB I/O) ---
80	  // Prevents successful write operations from completing without an audit record.
81	  // This is a fast, synchronous check that replaces the response payload inline.
82	  fastify.addHook('onSend', async (request, reply, payload) => {
83	    if (request._auditWritten) return payload;
84	    if (request._auditHookRan) return payload;
85	    request._auditHookRan = true;
86	    if (!request.url.startsWith('/api/v1/') || request.url === '/api/v1/health') return payload;
