88	    // Successful write operations: MUST have called writeAudit() — invariant violation.
89	    // Replace the response with a 500 to block the un-audited write from reaching the client.
90	    if (WRITE_METHODS.has(request.method) && reply.statusCode < 400) {
91	      const msg = `AUDIT_VIOLATION: ${request.method} ${request.url} (${reply.statusCode}) completed without writeAudit(). Add auditContext + writeAudit() to this route.`;
92	      request.log.fatal({ method: request.method, url: request.url, statusCode: reply.statusCode }, msg);
93	      reply.code(500);
94	      reply.header('content-type', 'application/json');
95	      return JSON.stringify({ error: 'AUDIT_VIOLATION', message: msg });
96	    }
97	
98	    return payload;
99	  });
100	
101	  // --- onResponse: async audit write for reads and failed writes ---
102	  // Runs after the response is sent. For reads and error responses, writes an audit
103	  // record with retry. On failure, logs at FATAL for mandatory reconciliation.
104	  // Write operations are already audited by writeAudit() in the handler (fail-closed).
105	  fastify.addHook('onResponse', async (request, reply) => {
106	    if (request._auditWritten) return;
107	    if (!request.url.startsWith('/api/v1/') || request.url === '/api/v1/health') return;
108	    // Skip write-audit violations (already replaced with 500 in onSend)
109	    if (WRITE_METHODS.has(request.method) && reply.statusCode < 400) return;
110	
111	    const entry = buildAuditEntry(request);
112	    const ok = await insertAuditWithRetry(fastify.db, entry, request.log);
113	    if (!ok) {
114	      request.log.fatal({
115	        auditEntry: entry,
116	        method: request.method,
117	        url: request.url,
118	        statusCode: reply.statusCode,
119	      }, 'AUDIT_PERSISTENCE_FAILURE: Protected action completed without durable audit record. Entry logged for mandatory reconciliation.');
120	    }
121	  });
122	}
123	
124	function inferResourceType(url: string): string {
125	  const segments = url.replace('/api/v1/', '').split('/');
126	  return segments[0] || 'unknown';
127	}
128	
129	export default fp(auditLogPlugin, {
130	  name: 'audit-log',
131	  dependencies: ['database'],
132	  fastify: '5.x',
133	});
